(async () => {
const config = {
  appUrl: String($env.APP_URL || '').trim(),
  webhookSecret: String($env.N8N_WEBHOOK_SECRET || '').trim(),
  anthropicApiKey: String($env.ANTHROPIC_API_KEY || '').trim(),
  v3MaxRetries: String($env.V3_MAX_RETRIES || '').trim(),
  v3RetryBaseMs: String($env.V3_RETRY_BASE_MS || '').trim(),
  v3RetryCapMs: String($env.V3_RETRY_CAP_MS || '').trim()
};

const required = {
  APP_URL: config.appUrl,
  N8N_WEBHOOK_SECRET: config.webhookSecret,
  ANTHROPIC_API_KEY: config.anthropicApiKey,
  V3_MAX_RETRIES: config.v3MaxRetries,
  V3_RETRY_BASE_MS: config.v3RetryBaseMs,
  V3_RETRY_CAP_MS: config.v3RetryCapMs
};

const missing = Object.entries(required)
  .filter(([_, value]) => !String(value || '').trim())
  .map(([name]) => name);

if (missing.length > 0) {
  throw new Error('MISSING_ENV_NAMES:' + missing.join(','));
}

const payload = $input.first().json || {};
return [{ json: { ...payload, config } }];
})();

(async () => {
const input = $input.first().json || {};
const config = input.config || {};
const body = input.body || {};
const headers = input.headers || {};
const runId = 'tailor_v3_' + String($execution.id || Date.now());

const incomingSecret = String(headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || '').trim();
if (!incomingSecret || incomingSecret !== String(config.webhookSecret || '').trim()) {
  return [{ json: { ok: false, status: 401, error: 'unauthorized', runId } }];
}

const userId = String(body.userId || '').trim();
const jobId = String(body.jobId || '').trim();
const jobDescription = String(body.jobDescription || '').trim();
const masterCvText = String(body.masterCvText || '').trim();
const jobTitle = String(body.jobTitle || '').trim();
const company = String(body.company || '').trim();
const additionalContext = String(body.additionalContext || '').trim();

if (!userId || !jobId || !jobDescription || !masterCvText) {
  return [{
    json: {
      ok: false,
      status: 400,
      error: 'invalid_payload',
      runId,
      missing: [
        !userId ? 'userId' : null,
        !jobId ? 'jobId' : null,
        !jobDescription ? 'jobDescription' : null,
        !masterCvText ? 'masterCvText' : null
      ].filter(Boolean)
    }
  }];
}

const scoringPrompt = [
  'Return ONLY JSON:',
  '{"compatibility_score":0-100,"ats_keywords":[],"matching_strengths":[],"gaps":[],"recommendation":"apply|stretch|skip"}',
  'Job description:',
  jobDescription.slice(0, 4000),
  'Candidate CV:',
  masterCvText.slice(0, 7000),
  additionalContext ? ('Additional confirmed candidate context:\n' + additionalContext.slice(0, 2500)) : ''
].join('\n');

return [{
  json: {
    ok: true,
    status: 200,
    runId,
    userId,
    jobId,
    jobTitle: jobTitle || 'Untitled Position',
    company: company || 'Unknown Company',
    jobDescription,
    masterCvText,
    additionalContext,
    scoringPrompt,
    appUrl: String(config.appUrl || '').trim(),
    webhookSecret: String(config.webhookSecret || '').trim(),
    anthropicApiKey: String(config.anthropicApiKey || '').trim()
  }
}];
})();

(async () => {
const prev = $('Validate and Prepare Single v3').first().json || {};
const resp = $input.first().json || {};

function parseJsonObject(text) {
  const raw = String(text || '');
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start < 0 || end <= start) return null;
  try {
    return JSON.parse(raw.slice(start, end + 1));
  } catch {
    return null;
  }
}

const text = resp.content && resp.content[0] ? String(resp.content[0].text || '') : '';
const parsed = parseJsonObject(text);
if (!parsed || typeof parsed !== 'object') {
  return [{
    json: {
      ok: false,
      status: 500,
      error: 'single_tailor_failed',
      reasonCode: 'SCORING_PARSE_FAILURE',
      runId: prev.runId,
      userId: prev.userId,
      jobId: prev.jobId
    }
  }];
}

const atsKeywords = Array.isArray(parsed.ats_keywords) ? parsed.ats_keywords.slice(0, 12) : [];
const matchingStrengths = Array.isArray(parsed.matching_strengths) ? parsed.matching_strengths.slice(0, 6) : [];
const gaps = Array.isArray(parsed.gaps) ? parsed.gaps.slice(0, 6) : [];
const recommendation = String(parsed.recommendation || 'stretch');
const compatibilityScore = Number(parsed.compatibility_score || 0);

const tailorPrompt = [
  'Return ONLY JSON:',
  '{"tailored_cv_markdown":"...","motivation_letter_markdown":"..."}',
  'Never fabricate facts. Use only candidate-provided information.',
  'ATS keywords:',
  JSON.stringify(atsKeywords),
  'Job title:',
  prev.jobTitle || 'Untitled Position',
  'Company:',
  prev.company || 'Unknown Company',
  'Job description:',
  String(prev.jobDescription || '').slice(0, 4000),
  'Candidate CV:',
  String(prev.masterCvText || '').slice(0, 7000),
  prev.additionalContext ? ('Additional confirmed candidate context:\n' + String(prev.additionalContext).slice(0, 2500)) : ''
].join('\n');

return [{
  json: {
    ...prev,
    ok: true,
    status: 200,
    compatibilityScore,
    atsKeywords,
    matchingStrengths,
    gaps,
    recommendation,
    tailorPrompt
  }
}];
})();

(async () => {
const prev = $('Parse Scoring Response v3').first().json || {};
const resp = $input.first().json || {};

function parseJsonObject(text) {
  const raw = String(text || '');
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start < 0 || end <= start) return null;
  try {
    return JSON.parse(raw.slice(start, end + 1));
  } catch {
    return null;
  }
}

const text = resp.content && resp.content[0] ? String(resp.content[0].text || '') : '';
const parsed = parseJsonObject(text);
if (!parsed || typeof parsed !== 'object') {
  return [{
    json: {
      ok: false,
      status: 500,
      error: 'single_tailor_failed',
      reasonCode: 'TAILORING_PARSE_FAILURE',
      runId: prev.runId,
      userId: prev.userId,
      jobId: prev.jobId
    }
  }];
}

const idempotencyKey = 'tailor_v3:' + prev.userId + ':' + prev.jobId;

return [{
  json: {
    ...prev,
    ok: true,
    status: 200,
    idempotencyKey,
    tailoredCvMarkdown: String(parsed.tailored_cv_markdown || ''),
    coverLetterMarkdown: String(parsed.motivation_letter_markdown || '')
  }
}];
})();

